#include <stdio.h>
#include <stdlib.h>
int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}
int main() {
    int n;
    scanf("%d", &n);
    int arr[n];
    for (int i = 0; i < n; i++) {
        scanf("%d", &arr[i]);
    }
    qsort(arr, n, sizeof(int), compare);
    int mid = n / 2;
    int count = 0;
    for (int i = 0; i < mid; i++) {
        if (arr[i] < arr[mid]) {
            count++;
        }
    }
    printf("%d\n", count);
    return 0;
}

